def backtrack(start, path, target):
    if target < 0:
        return
    if len(path) == k:
        if target == 0:
            result.append(' '.join(map(str, path)))
        return
    for i in range(start, 10):
        backtrack(i + 1, path + [i], target - i)

result = []
backtrack(1, [], n)
if result:
    print('\n'.join(sorted(result)))
else:
    print(-1)

