#include <bits/stdc++.h>
using namespace std;
int main(){
    int k, n;
    if(!(cin >> k >> n)) return 0;
    vector<string> result;
    function<void(int, vector<int>, int)> backtrack = 
        [&backtrack, &result, &k, &n](int start, vector<int> path, int target){
            if (target < 0) return;
            if (path.size() == k) {
                if (target == 0) {
                    string str;
                    for (int i = 0; i < path.size(); i++) {
                        str += to_string(path[i]);
                        if (i != path.size() - 1) str += ' ';
                    }
                    result.push_back(str);
                }
                return;
            }
            for (int i = start; i <= 9; i++) {
                path.push_back(i);
                backtrack(i + 1, path, target - i);
                path.pop_back();
            }
        };
    backtrack(1, {}, n);
    if (!result.empty()) {
        sort(result.begin(), result.end());
        for (int i = 0; i < result.size(); i++) {
            cout << result[i] << endl;
        }
    } else {
        cout << -1 << endl;
    }
    return 0;
}
